473: 	updatedEntries, err := managedFieldsHandler.ToParent(scale.ManagedFields)
474: 	if err != nil {
475: 		return nil, err
476: 	}
477: 	deployment.ManagedFields = updatedEntries
478: 
479: 	return deployment, nil
